{
  "name": "Commonwealth Coordinated Care Plus (CCC+) Waiver",
  "eligibility": {
    "age": null,
    "income_limits": "Must meet Virginia Medicaid financial eligibility (income and assets). No specific dollar amounts or household size table provided in sources; spousal impoverishment protections apply where only the applicant spouse's income is counted toward eligibility, and income can be transferred to the non-applicant spouse as a Spousal Income Allowance. Use Virginia Medicaid Eligibility Test for details.[1]",
    "asset_limits": "Must meet Virginia Medicaid financial eligibility (income and assets). No specific dollar amounts provided; spousal protections apply.[1]",
    "other_requirements": [
      "Virginia resident.",
      "Aged 65+ or under 65 and disabled (physical disability, chronically ill, or severely impaired with loss of vital body function).[1][2]",
      "Nursing Facility Level of Care (NFLOC) determined by Virginia Uniform Assessment Instrument (UAI), assessing Activities of Daily Living (ADLs) like transferring, mobility, bathing, toileting, eating; living situation, physical health, behavioral issues (e.g., for dementia); or Hospital Level of Care requiring medical device (e.g., ventilator) and ongoing skilled nursing to prevent death/disability.[1][2][3]",
      "Medicaid eligible.[2]",
      "At imminent risk of nursing facility placement without waiver services.[3]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Home and Community-Based Services (HCBS) including: Respite (480 hours per State fiscal year, July 1-June 30); Environmental Modifications (EM, up to $5,000 per individual per calendar year); Assistive Technology (AT, up to $5,000 per individual per calendar year); Private Duty Nursing (up to 112 hours per week); Transition Services (up to $5,000 per individual per lifetime). Other supports for older adults, physical disabilities, chronic illness; enrolled in managed care receive transition supports. Waiver reimbursement rates on DMAS site.[2][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Request LTSS Screening through local Department of Social Services (DSS); Community Based Screening Team (social worker and health dept. nurse) assesses need.[2]",
      "If hospitalized, screening by discharge planner.[2]",
      "Medicaid application: Online at CommonHelp.virginia.gov; phone Cover Virginia Call Center 1-833-522-5582 (TDD 1-888-221-1590); local DSS for paper application and Appendix D for long-term services.[2]",
      "Post-approval: Choose services; screening team assists with local providers.[2]"
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": "No current waiting list.[5]",
    "forms": [
      "Appendix D (specific to long-term services and supports).[2]"
    ],
    "documents": [
      "Documents for Medicaid eligibility and LTSS screening (not detailed; prepare income/asset proof, medical records for NFLOC assessment via UAI).[1][2]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Screenings by local DSS and health departments; providers located by screening team in applicant's area. Examples: Fairfax County - under 18 call 703-222-0880, 18+ call 703-324-7948.[2][6]",
    "offices_or_providers": [
      "Local Departments of Social Services (statewide).[2][5]",
      "Cover Virginia Call Center: 1-833-522-5582.[2]"
    ]
  },
  "official_source": "https://www.dmas.virginia.gov/for-members/benefits-and-services/waivers/ccc-plus-waiver/[2]",
  "gotchas": [
    "Must meet Medicaid financial eligibility first; applying over limits leads to denial.[1]",
    "Dementia diagnosis alone does not qualify; must meet NFLOC via UAI.[1]",
    "Services more limited than DD waivers; can use CCC+ while on DD waitlist.[5][6]",
    "Must be at imminent risk of NF placement.[3]"
  ],
  "data_shape_notes": "No waitlist unlike some waivers; eligibility ties to Medicaid with NFLOC via UAI tool; services have hard caps (e.g., 480 respite hours/year, 112 nursing hours/week); screenings always local via DSS/health depts."
}

{
  "name": "Virginia Adult Services Program",
  "eligibility": {
    "age": "60 years or older for Adult Protective Services; 18+ for incapacitated adults; no strict age for general homemaker/chore services but targeted at elderly/disabled adults[2][7]",
    "income_limits": "No specific statewide income limits stated for Adult Services Program; financial eligibility assessed locally and may tie to Medicaid thresholds like $2,982/month for single applicants in related long-term care programs (2026 figures). Varies by service and local department; no table provided for household sizes[1][4]",
    "asset_limits": "No specific asset limits stated for Adult Services Program; related Medicaid programs limit singles to $2,000 (exempt: primary home equity up to $603,000, one vehicle, personal belongings, furniture)[1][3]",
    "other_requirements": ["Virginia resident", "Functional need (e.g., dependent in ADLs/IADLs like meal prep, housekeeping, money management)", "Risk of abuse/neglect/exploitation or need for protective services", "No citizenship or residency duration requirement", "Anyone may apply; equal treatment regardless of race, color, religion, sex, national origin, or handicap[4][7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Homemaker services, chore/companionship (up to 15 hours/week in some areas like Companion Services), screenings for assisted living/nursing home/home-based care/adult day care/waiver services, Adult Protective Services (APS) including health/housing/social/legal arrangements to prevent mistreatment, adult day centers for health/social support[2][6][7]",
    "varies_by": "priority_tier|region"
  },
  "application": {
    "methods": ["In-person or mail via local Department of Social Services (DSS) office (e.g., King George County sample form)", "Phone: local DSS or state hotline (specific number not listed; contact local office)", "Assistance available to complete application on request[4][6]"],
    "processing_time": "Eligibility decision within 45 days; services begin within 45 days if eligible[4]",
    "waitlist": "Depends on available funds/services; optional services subject to availability[4]",
    "forms": ["Adult Services Application (local DSS-specific, e.g., King George County PDF)[4]"],
    "documents": ["Proof of income (pay stubs, permission to contact agencies)", "Complete/accurate personal information; notify of changes within 10 days[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered by local departments of social services (DSS); available countywide with no specific county restrictions[4][7]",
    "regional_variations": "Services/providers approved locally (e.g., homemaker providers 18+, chore/companions 16+ with competence check); hours like 15/week in Lee County; wait times/funding vary by local department availability[2][6]",
    "offices_or_providers": ["Local DSS offices (e.g., Lee County DSS, King George County DSS)[4][6]"]
  },
  "official_source": "https://www.dss.virginia.gov/adults.cgi",
  "gotchas": ["Not Medicaid (separate financial eligibility); services optional and funding-limited", "Must report changes within 10 days or risk prosecution for inaccurate info", "Targeted at at-risk elderly/disabled; anyone can apply but priority for protective needs", "Local variations in providers/hours; no guaranteed hours statewide[2][4][7]"],
  "data_shape_notes": "Administered locally by 120+ DSS offices with state oversight; no fixed statewide income/asset test; services scale by assessed need/priority and local funding; provider approvals vary by locality"
}

{
  "name": "SeniorNavigator",
  "eligibility": {
    "age": null,
    "income_limits": "No specific income limits; it is a resource directory, not a direct benefits program with financial thresholds[1][3].",
    "asset_limits": "No asset limits; not applicable as this is an informational tool[1][3].",
    "other_requirements": ["Open to older adults, people with disabilities, veterans, families, and caregivers in Virginia; no formal eligibility to use the directory[1][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Online searchable database of over 27,000 programs covering health, housing, transportation, employment, financial planning, technology, and more; includes eligibility criteria, intake processes, costs, fact sheets, articles, books, videos, and 'Ask an Expert' for personalized advice; specialized portals for seniors, disabilities, veterans, and caregivers[1].",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Online: virginianavigator.org and specialized sites (e.g., for seniors, disabilities, veterans, caregivers); search by topic and city/county[1][3]"],
    "processing_time": "Immediate access to directory; no formal application processing[1].",
    "waitlist": null,
    "forms": ["No specific forms required to use the directory[1][3]"],
    "documents": ["None required to search or use the resource[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Statewide for Virginia, searchable by specific city or county[1].",
    "regional_variations": "Services listed vary by locality (city/county) with local providers, government agencies, nonprofits; e.g., Henrico County partnership highlights resources for Henrico, Charles City, New Kent[1][3].",
    "offices_or_providers": ["Searchable local providers including government agencies, nonprofits, geriatricians; Henrico Area Mental Health & Developmental Services partnership[1][3]"]
  },
  "official_source": "https://www.virginianavigator.org/",
  "gotchas": ["Not a direct service or benefits program—it's a navigator tool to find and compare other programs' eligibility, applications, and costs; users must follow through on listed services separately, which may have their own waitlists or requirements[1][3]", "Over 1 million annual visits indicate high usage, but success depends on acting on referrals[1]"],
  "data_shape_notes": "Resource directory with drill-down details on 27,000+ programs; varies by locality with no direct eligibility test for the tool itself; public-private nonprofit partnership unique in using technology for customized local searches[1]"
}
